.darma-loader-uiverse-dashboard-shimmer {
  display: grid;
  width: 118px;
  gap: 10px;
}
.darma-loader-uiverse-dashboard-shimmer i {
  display: block;
  height: 10px;
  border-radius: 999px;
  background: linear-gradient(90deg, color-mix(in srgb, var(--loader-color, #06b6d4) 12%, transparent), color-mix(in srgb, var(--loader-color, #06b6d4) 34%, transparent), color-mix(in srgb, var(--loader-color, #06b6d4) 12%, transparent));
  background-size: 220% 100%;
  animation: darma-loader-uiverse-dashboard-shimmer-skeletonShimmer 1.1s linear infinite;
}
.darma-loader-uiverse-dashboard-shimmer i:first-child { width: 72px; height: 44px; border-radius: 14px; }
.darma-loader-uiverse-dashboard-shimmer i:nth-child(2) { width: 100%; }
.darma-loader-uiverse-dashboard-shimmer i:nth-child(3) { width: 76%; }
.darma-loader-uiverse-dashboard-shimmer i:nth-child(4) { width: 54%; }
@keyframes darma-loader-uiverse-dashboard-shimmer-skeletonShimmer { to { background-position: -220% 0; } }

